+import { randomBytes, randomUUID } from "node:crypto";
+
+export function generateSecureUuid(): string {
+  return randomUUID();
+}
+
+export function generateSecureToken(bytes = 16): string {
+  return randomBytes(bytes).toString("base64url");
+}

